const S = {
  nav: { position: "sticky", top: 0, zIndex: 100, background: "rgba(10,10,9,.95)", backdropFilter: "blur(16px)", borderBottom: "1px solid #272724", padding: "0 1.5rem" },
  navInner: { maxWidth: 1100, margin: "0 auto", display: "flex", alignItems: "center", justifyContent: "space-between", height: 58 },
  logo: { fontSize: 17, fontWeight: 800, color: "#e8c84a", display: "flex", alignItems: "center", gap: 8 },
  logoDot: { width: 7, height: 7, borderRadius: "50%", background: "#e8c84a" },
  page: { maxWidth: 1100, margin: "0 auto", padding: "2rem 1.5rem" },
  tag: (color) => ({ display: "inline-block", background: color + "18", border: `1px solid ${color}44`, borderRadius: 20, padding: "3px 12px", fontSize: 10, fontWeight: 700, color, letterSpacing: 1, textTransform: "uppercase", fontFamily: "monospace", marginBottom: 6 }),
  card: { background: "#1a1a18", border: "1px solid #272724", borderRadius: 14, padding: "1.25rem" },
  rmCard: { background: "#1a1a18", border: "1px solid #272724", borderRadius: 14, padding: "1rem" },
  dayCard: (done) => ({ background: done ? "#0a1f14" : "#181816", border: `1px solid ${done ? "rgba(76,175,125,.4)" : "#272724"}`, borderRadius: 8, padding: "7px 5px", cursor: "pointer", transition: "all .18s", userSelect: "none" }),
  resCard: { background: "#1a1a18", border: "1px solid #272724", borderRadius: 9, padding: "1rem" },
  btn: (color = "#e8c84a") => ({ background: color, color: color === "#e8c84a" ? "#0a0a09" : "#fff", border: "none", borderRadius: 9, padding: "11px 20px", fontSize: 13, fontWeight: 700, cursor: "pointer", transition: "all .2s" }),
  btnGhost: { background: "transparent", border: "1px solid #272724", color: "#a8a49a", borderRadius: 8, padding: "7px 14px", fontSize: 12, fontWeight: 600, cursor: "pointer" },
  pbar: { height: 7, background: "#181816", borderRadius: 4, overflow: "hidden" },
};

const WK_COLORS = { wk1: "#5b9cf6", wk2: "#e8a030", wk3: "#4caf7d", wk4: "#e05a4e", wk5: "#b57cf6", wk6: "#3dd6c8" };

// ─────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────
function ExamCRKApp() {
  const params = useSearchParams();
  const router = useRouter();
  const initialExam = params.get("exam") || null;

  const [examId, setExamId] = useState(initialExam);
  const [activeSubject, setActiveSubject] = useState(null);
  const [progress, setProgress] = useState({});
  const [streak, setStreak] = useState(0);

  // Load saved progress from localStorage
  useEffect(() => {
    try {
      const saved = JSON.parse(localStorage.getItem("examcrk_progress_v2") || "{}");
      setProgress(saved);
      setStreak(parseInt(localStorage.getItem("examcrk_streak") || "0"));
    } catch {}
  }, []);

  const saveProgress = (newProgress) => {
    localStorage.setItem("examcrk_progress_v2", JSON.stringify(newProgress));
    setProgress(newProgress);
  };

  const subjects = examId ? (ALL_SUBJECTS[examId] || []) : [];

  const getDone = (subjectId) => {
    const subj = subjects.find(s => s.id === subjectId);
    if (!subj) return { done: 0, total: 0, pct: 0 };
    const total = subj.weeks.reduce((a, w) => a + w.days.length, 0);
    const done = (progress[examId]?.[subjectId] || []).filter(Boolean).length;
    return { done, total, pct: total ? Math.round(done / total * 100) : 0 };
  };

  const getTotalDone = () => {
    let done = 0, total = 0;
    subjects.forEach(s => { const r = getDone(s.id); done += r.done; total += r.total; });
    return { done, total, pct: total ? Math.round(done / total * 100) : 0 };
  };

  const toggleDay = (subjectId, idx) => {
    const newP = { ...progress };
    if (!newP[examId]) newP[examId] = {};
    const subj = subjects.find(s => s.id === subjectId);
    const total = subj.weeks.reduce((a, w) => a + w.days.length, 0);
    if (!newP[examId][subjectId]) newP[examId][subjectId] = new Array(total).fill(false);
    const wasOff = !newP[examId][subjectId][idx];
    newP[examId][subjectId] = [...newP[examId][subjectId]];
    newP[examId][subjectId][idx] = wasOff;
    if (wasOff) {
      const newStreak = streak + 1;
      setStreak(newStreak);
      localStorage.setItem("examcrk_streak", newStreak);
    }
    saveProgress(newP);
  };

  const resetSubject = (subjectId) => {
    const subj = subjects.find(s => s.id === subjectId);
    const total = subj.weeks.reduce((a, w) => a + w.days.length, 0);
    const newP = { ...progress };
    if (!newP[examId]) newP[examId] = {};
    newP[examId][subjectId] = new Array(total).fill(false);
    saveProgress(newP);
  };

  // ── EXAM SELECTOR ──────────────────────────────────────────
  if (!examId) {
    return (
      <>
        <nav style={S.nav}>
          <div style={S.navInner}>
            <div style={S.logo}><div style={S.logoDot} />ExamCRK Pro</div>
            <Link href="/dashboard"><button style={S.btnGhost}>← Dashboard</button></Link>
          </div>
        </nav>
        <div style={{ ...S.page, textAlign: "center", paddingTop: "4rem" }}>
          <h1 style={{ fontSize: "clamp(2rem,5vw,3rem)", fontWeight: 800, letterSpacing: -2, marginBottom: 12 }}>
            Select your <span style={{ color: "#e8c84a" }}>exam</span>
          </h1>
          <p style={{ fontSize: 14, color: "#a8a49a", marginBottom: "3rem" }}>Pick an exam to get your full roadmap and day-strike calendar.</p>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))", gap: 12, maxWidth: 700, margin: "0 auto" }}>
            {Object.entries(EXAM_META).map(([id, meta]) => (
              <div key={id} onClick={() => { setExamId(id); setActiveSubject(null); }}
                style={{ ...S.card, cursor: "pointer", textAlign: "center", padding: "1.5rem 1rem", transition: "all .2s" }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = meta.color; e.currentTarget.style.transform = "translateY(-3px)"; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = "#272724"; e.currentTarget.style.transform = "none"; }}
              >
                <div style={{ fontSize: 28, marginBottom: 10 }}>{meta.icon}</div>
                <div style={{ fontSize: 13, fontWeight: 700 }}>{meta.name}</div>
              </div>
            ))}
          </div>
        </div>
      </>
    );
  }

  const meta = EXAM_META[examId];
  const t = getTotalDone();

  // ── SUBJECT VIEW ───────────────────────────────────────────
  if (activeSubject) {
    const subj = subjects.find(s => s.id === activeSubject);
    if (!subj) { setActiveSubject(null); return null; }
    const total = subj.weeks.reduce((a, w) => a + w.days.length, 0);
    const prog = progress[examId]?.[subj.id] || new Array(total).fill(false);
    const done = prog.filter(Boolean).length;
    const pct = total ? Math.round(done / total * 100) : 0;

    let dayIdx = 0;

    return (
      <>
        <nav style={S.nav}>
          <div style={S.navInner}>
            <div style={S.logo}><div style={S.logoDot} />ExamCRK Pro</div>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <span style={{ fontSize: 12, color: "#e8a030", fontFamily: "monospace", background: "#1e120830", border: "1px solid #e8a03044", borderRadius: 20, padding: "3px 12px" }}>⚡ {streak} day streak</span>
              <Link href="/dashboard"><button style={S.btnGhost}>← Dashboard</button></Link>
            </div>
          </div>
        </nav>

        <div style={S.page}>
          {/* Header */}
          <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: "2rem", paddingBottom: "1.5rem", borderBottom: "1px solid #272724" }}>
            <button style={S.btnGhost} onClick={() => setActiveSubject(null)}>← Back</button>
            <div>
              <div style={{ fontSize: 22, fontWeight: 800, letterSpacing: -.5 }}>{subj.name}</div>
              <div style={{ fontSize: 11, color: "#5e5c57", fontFamily: "monospace", marginTop: 2 }}>{total} days · {subj.weeks.length} weeks</div>
            </div>
          </div>

          {/* Insight cards */}
          <div style={{ borderRadius: 12, padding: "1.25rem 1.5rem", marginBottom: "1rem", background: subj.insightColor, borderLeft: `3px solid ${subj.insightBorder}` }}>
            <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", fontFamily: "monospace", opacity: .65, marginBottom: 6 }}>{subj.insight.label}</div>
            <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 8, color: subj.insightBorder }}>{subj.insight.title}</div>
            <div style={{ fontSize: 13, color: "#a8a49a", lineHeight: 1.8 }}>{subj.insight.body}</div>
          </div>
          <div style={{ borderRadius: 12, padding: "1.25rem 1.5rem", marginBottom: "1.5rem", background: "#0a1f14", borderLeft: "3px solid #4caf7d" }}>
            <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", fontFamily: "monospace", opacity: .65, marginBottom: 6, color: "#4caf7d" }}>Pro tip</div>
            <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 8, color: "#4caf7d" }}>{subj.insight2.title}</div>
            <div style={{ fontSize: 13, color: "#a8a49a", lineHeight: 1.8 }}>{subj.insight2.body}</div>
          </div>

          {/* Roadmap */}
          <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", fontFamily: "monospace", color: "#5e5c57", marginBottom: 12 }}>Roadmap</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 10, marginBottom: "1.5rem" }}>
            {subj.roadmap.map((r, i) => (
              <div key={i} style={S.rmCard}>
                <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", fontFamily: "monospace", marginBottom: 4, color: ["#5b9cf6", "#e8a030", "#4caf7d", "#b57cf6"][i] }}>{r.phase}</div>
                <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 3 }}>{r.title}</div>
                <div style={{ fontSize: 10, color: "#5e5c57", fontFamily: "monospace", marginBottom: 10 }}>{r.dur}</div>
                <ul style={{ listStyle: "none" }}>
                  {r.topics.map((topic, j) => (
                    <li key={j} style={{ fontSize: 11.5, color: "#a8a49a", padding: "3px 0", borderBottom: j < r.topics.length - 1 ? "1px solid #272724" : "none", display: "flex", gap: 5, lineHeight: 1.4 }}>
                      <span style={{ color: "#5e5c57", flexShrink: 0, fontSize: 10 }}>→</span>{topic}
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>

          {/* Progress row */}
          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: "1.5rem", background: "#1a1a18", border: "1px solid #272724", borderRadius: 14, padding: "1rem 1.25rem" }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 12, color: "#a8a49a", marginBottom: 5 }}>Progress — {total} days</div>
              <div style={S.pbar}><div style={{ height: "100%", borderRadius: 4, background: subj.color, width: pct + "%", transition: "width .4s" }} /></div>
            </div>
            <div style={{ fontSize: 20, fontWeight: 800, fontFamily: "monospace", color: subj.color }}>{done}/{total}</div>
            <button style={S.btnGhost} onClick={() => resetSubject(subj.id)}>Reset</button>
          </div>

          {/* Day calendar */}
          {subj.weeks.map((wk, wi) => {
            const wkColor = WK_COLORS[wk.cls] || "#e8c84a";
            return (
              <div key={wi} style={{ marginBottom: "1.5rem" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                  <span style={{ fontSize: 10, fontWeight: 700, padding: "3px 12px", borderRadius: 20, fontFamily: "monospace", background: wkColor + "22", color: wkColor }}>{wk.label}</span>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 5 }}>
                  {wk.days.map((d, di) => {
                    const idx = dayIdx++;
                    const isDone = prog[idx] || false;
                    return (
                      <div key={di} style={S.dayCard(isDone)} onClick={() => toggleDay(subj.id, idx)}>
                        <div style={{ fontSize: 9, color: "#5e5c57", fontFamily: "monospace", marginBottom: 2 }}>Day {idx + 1}</div>
                        <div style={{ fontSize: 10, fontWeight: 500, color: isDone ? "#4caf7d" : "#f0ede4", lineHeight: 1.3 }}>{d.t}</div>
                        {d.q > 0 && <div style={{ fontSize: 9, color: isDone ? "rgba(76,175,125,.6)" : "#5e5c57", marginTop: 2, fontFamily: "monospace" }}>{d.q} qs</div>}
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}

          {/* Resources */}
          <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", fontFamily: "monospace", color: "#5e5c57", marginBottom: 12 }}>Resources</div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 10, marginBottom: "2rem" }}>
            {subj.resources.map((r, i) => (
              <div key={i} style={S.resCard}>
                <div style={{ fontSize: 10, color: "#5e5c57", fontFamily: "monospace", textTransform: "uppercase", letterSpacing: .5, marginBottom: 4 }}>{r.type}</div>
                <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 2 }}>{r.name}</div>
                <div style={{ fontSize: 11, color: "#a8a49a" }}>{r.desc}</div>
              </div>
            ))}
          </div>
        </div>
      </>
    );
  }

  // ── EXAM DASHBOARD ─────────────────────────────────────────
  return (
    <>
      <nav style={S.nav}>
        <div style={S.navInner}>
          <div style={S.logo}><div style={S.logoDot} />ExamCRK Pro</div>
          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <span style={{ fontSize: 12, color: "#e8a030", fontFamily: "monospace", background: "#1e120830", border: "1px solid #e8a03044", borderRadius: 20, padding: "3px 12px" }}>⚡ {streak} day streak</span>
            <button style={S.btnGhost} onClick={() => { setExamId(null); setActiveSubject(null); }}>Change exam</button>
            <Link href="/dashboard"><button style={S.btnGhost}>← Dashboard</button></Link>
          </div>
        </div>
      </nav>

      <div style={S.page}>
        {/* Hero */}
        <div style={{ marginBottom: "2rem" }}>
          <div style={{ fontSize: 11, color: "#5e5c57", fontFamily: "monospace", letterSpacing: 1, textTransform: "uppercase", marginBottom: 8 }}>
            {meta.icon} {meta.name}
          </div>
          <h1 style={{ fontSize: "clamp(1.8rem,4vw,2.8rem)", fontWeight: 800, letterSpacing: -1.5, lineHeight: 1.1, marginBottom: 8 }}>
            Crack <span style={{ color: meta.color }}>{meta.name}</span><br />one day at a time.
          </h1>
          <p style={{ fontSize: 14, color: "#a8a49a", lineHeight: 1.7 }}>
            Your complete preparation companion — roadmaps, daily plans, and pro tips for all subjects.
          </p>
        </div>

        {/* Stats */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10, marginBottom: "1.5rem" }}>
          {[
            { num: t.done, lbl: "days done" },
            { num: t.total, lbl: "total days" },
            { num: subjects.length, lbl: "subjects" },
            { num: t.pct + "%", lbl: "complete" },
          ].map((s, i) => (
            <div key={i} style={{ ...S.card, textAlign: "center" }}>
              <div style={{ fontSize: 26, fontWeight: 800, color: meta.color }}>{s.num}</div>
              <div style={{ fontSize: 11, color: "#5e5c57", fontFamily: "monospace", marginTop: 4 }}>{s.lbl}</div>
            </div>
          ))}
        </div>

        {/* Overall progress */}
        <div style={{ ...S.card, marginBottom: "1.5rem" }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 10 }}>
            <span style={{ fontSize: 13, fontWeight: 600 }}>Overall progress</span>
            <span style={{ fontSize: 12, fontFamily: "monospace", color: meta.color }}>{t.pct}%</span>
          </div>
          <div style={S.pbar}><div style={{ height: "100%", borderRadius: 4, background: meta.color, width: t.pct + "%", transition: "width .5s" }} /></div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginTop: 14 }}>
            {subjects.map(s => {
              const r = getDone(s.id);
              return (
                <div key={s.id} style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <div style={{ width: 7, height: 7, borderRadius: "50%", background: s.color, flexShrink: 0 }} />
                  <span style={{ fontSize: 11, color: "#a8a49a", flex: 1 }}>{s.name}</span>
                  <div style={{ flex: 1.5, height: 3, background: "#181816", borderRadius: 2, overflow: "hidden" }}>
                    <div style={{ height: "100%", background: s.color, width: r.pct + "%", transition: "width .5s" }} />
                  </div>
                  <span style={{ fontSize: 11, fontFamily: "monospace", color: "#5e5c57", minWidth: 32, textAlign: "right" }}>{r.pct}%</span>
                </div>
              );
            })}
          </div>
        </div>

        {/* Subject cards */}
        <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", fontFamily: "monospace", color: "#5e5c57", marginBottom: 12 }}>
          Choose a subject
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(2, 1fr)", gap: 12, marginBottom: "2rem" }}>
          {subjects.map(s => {
            const r = getDone(s.id);
            return (
              <div key={s.id} onClick={() => setActiveSubject(s.id)}
                style={{ ...S.card, cursor: "pointer", transition: "all .25s" }}
                onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-3px)"; e.currentTarget.style.borderColor = "#363632"; }}
                onMouseLeave={e => { e.currentTarget.style.transform = "none"; e.currentTarget.style.borderColor = "#272724"; }}
              >
                <div style={{ width: 40, height: 40, borderRadius: 10, background: s.color + "18", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, marginBottom: 12 }}>{s.icon}</div>
                <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 3 }}>{s.name}</div>
                <div style={{ fontSize: 10, color: "#5e5c57", fontFamily: "monospace", marginBottom: 12 }}>{s.weeks.reduce((a, w) => a + w.days.length, 0)} days · {s.weeks.length} weeks</div>
                <div style={S.pbar}><div style={{ height: "100%", borderRadius: 2, background: s.color, width: r.pct + "%", transition: "width .4s" }} /></div>
                <div style={{ fontSize: 10, fontFamily: "monospace", color: "#5e5c57", marginTop: 5 }}>{r.pct}% done</div>
              </div>
            );
          })}
        </div>
      </div>
    </>
  );
}

export default function ExamCRKPage() {
  return (
    <Suspense fallback={
      <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <div style={{ width: 36, height: 36, border: "2px solid #272724", borderTopColor: "#e8c84a", borderRadius: "50%", animation: "spin .7s linear infinite" }} />
      </div>
    }>
      <ExamCRKApp />
    </Suspense>
  );
}
